"use client";

import React, { useState } from "react";
import Header from "@/components/Header";
import ProductCard from "@/components/ProductCard";
import CartSidebar from "@/components/CartSidebar";
import PromoBanners from "@/components/PromoBanners";
import { products } from "@/components/data";

export interface CartItem {
 id: number;
 name: string;
 image: string;
 price: number;
 oldPrice?: number;
 quantity: number;
}

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([]);

 const addToCart = (product: typeof products[0]) => {
  setCart((prev) => {
   const found = prev.find((i) => i.id === product.id);
   if (found) return prev.map((i) => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
   return [...prev, {
    id: product.id, name: product.name, image: product.image ?? "",
    price: product.price, oldPrice: product.oldPrice, quantity: 1,
   }];
  });
 };

 const updateQty = (id: number, delta: number) => {
  setCart((prev) =>
   prev.map((i) => i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i).filter((i) => i.quantity > 0)
  );
 };

 const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);

 return (
  <div className="min-h-screen font-manrope" style={{ background: "#F2F2F4" }}>
   <Header />

   <main style={{ display: "flex", maxWidth: "100%" }}>

    {/* ═══ Left gray panel ═══ */}
    <aside
     className="hidden xl:block"
     style={{
      width: 130, flexShrink: 0,
      position: "sticky", top: 68, height: "calc(100vh - 68px)",
      background: "linear-gradient(180deg, #E6E6EA 0%, #DCDCE2 100%)",
     }}
    />

    {/* ═══ Center content ═══ */}
    <div style={{ flex: 1, minWidth: 0, padding: "18px 18px 40px" }}>
     <PromoBanners />

     {/* Section title */}
     <h2 style={{
      fontFamily: "var(--font-manrope)", fontSize: 20, fontWeight: 800,
      letterSpacing: "-0.03em", color: "#0F0F0F", marginBottom: 12,
     }}>
      Товары
     </h2>

     {/* ── 5-column product grid ── */}
     <div style={{
      display: "grid",
      gridTemplateColumns: "repeat(5, 1fr)",
      gap: "1px",
      background: "rgba(0,0,0,0.05)",
      borderRadius: 20,
      overflow: "hidden",
      boxShadow: "0 1px 4px rgba(0,0,0,0.04)",
     }}>
      {products.map((p) => (
       <ProductCard
        key={p.id}
        {...p}
        image={p.image ?? ""}
        onAdd={() => addToCart(p)}
       />
      ))}

      {/* "Больше" tile */}
      <div
       className="group"
       style={{
        background: "#fff", display: "flex", flexDirection: "column",
        alignItems: "center", justifyContent: "center", gap: 8,
        cursor: "pointer", minHeight: 180,
        transition: "background 0.2s",
       }}
       onMouseEnter={e => e.currentTarget.style.background = "#FAFAFA"}
       onMouseLeave={e => e.currentTarget.style.background = "#fff"}
      >
       <div style={{
        width: 38, height: 38, borderRadius: "50%",
        background: "#F0F0F4", display: "flex",
        alignItems: "center", justifyContent: "center",
        transition: "transform 0.25s cubic-bezier(0.34,1.56,0.64,1), background 0.2s",
        boxShadow: "0 1px 3px rgba(0,0,0,0.06)",
       }}
        className="group-hover:scale-110 group-hover:bg-white"
       >
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#8E8E93" strokeWidth="2.5" strokeLinecap="round">
         <path d="M5 12h14M12 5l7 7-7 7" />
        </svg>
       </div>
       <span style={{
        fontFamily: "var(--font-manrope)", fontSize: 11, fontWeight: 700,
        color: "#8E8E93", transition: "color 0.2s",
       }}
        className="group-hover:text-[#0F0F0F]"
       >
        Больше →
       </span>
      </div>
     </div>
    </div>

    {/* ═══ Right: Cart sidebar ═══ */}
    <aside
     className="hidden lg:block"
     style={{
      width: 340, flexShrink: 0,
      position: "sticky", top: 68, height: "calc(100vh - 68px)",
     }}
    >
     <CartSidebar cart={cart} onUpdateQuantity={updateQty} total={total} />
    </aside>
   </main>
  </div>
 );
}
