"use client";
import React from "react";
import { CartItem } from "@/app/page";

interface Props {
 cart: CartItem[];
 onUpdateQuantity: (id: number, delta: number) => void;
 total: number;
}

const CartSidebar: React.FC<Props> = ({ cart, onUpdateQuantity, total }) => {
 const totalItems = cart.reduce((s, i) => s + i.quantity, 0);

 return (
  <div style={{
   display: "flex", flexDirection: "column", height: "100%",
   background: "#fff", borderLeft: "1px solid rgba(0,0,0,0.06)",
  }}>

   {/* ── Header ── */}
   <div style={{ padding: "22px 22px 14px" }}>
    <h2 style={{
     fontFamily: "var(--font-manrope)", fontSize: 22, fontWeight: 800,
     letterSpacing: "-0.035em", color: "#0F0F0F", marginBottom: 16,
    }}>
     Корзина
    </h2>

    {/* Address + delivery */}
    <div style={{ display: "flex", alignItems: "center", gap: 6, cursor: "pointer", marginBottom: 2 }}>
     <span style={{
      fontFamily: "var(--font-manrope)", fontSize: 14, fontWeight: 700,
      color: "#0F0F0F", letterSpacing: "-0.015em",
     }}>
      улица Академика Янгеля
     </span>
     <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#8E8E93" strokeWidth="2.5">
      <path d="m6 9 6 6 6-6" />
     </svg>
    </div>
    <p style={{
     fontFamily: "var(--font-manrope)", fontSize: 12, fontWeight: 600,
     color: "#8E8E93", letterSpacing: "-0.01em",
    }}>
     Доставка 15 минут
    </p>
   </div>

   <div style={{ height: 1, background: "rgba(0,0,0,0.05)" }} />

   {/* ── Items ── */}
   <div className="smooth-scroll" style={{ flex: 1, overflowY: "auto", padding: "14px 22px" }}>
    {cart.length === 0 ? (
     <div style={{
      display: "flex", flexDirection: "column", alignItems: "center",
      justifyContent: "center", height: "100%", opacity: 0.35, paddingTop: 40,
     }}>
      <span style={{ fontSize: 42, marginBottom: 14 }}>🥐</span>
      <p style={{ fontFamily: "var(--font-manrope)", fontSize: 14, fontWeight: 700, color: "#0F0F0F" }}>
       Корзина пуста
      </p>
      <p style={{
       fontFamily: "var(--font-manrope)", fontSize: 12, fontWeight: 400,
       color: "#8E8E93", marginTop: 6, textAlign: "center", maxWidth: 170, lineHeight: 1.5,
      }}>
       Добавьте свежую выпечку из каталога
      </p>
     </div>
    ) : (
     <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
      {cart.map((item) => (
       <div
        key={item.id}
        style={{
         display: "flex", gap: 10, alignItems: "flex-start",
         padding: "6px 0",
         transition: "opacity 0.2s",
        }}
       >
        {/* Image */}
        <div style={{
         width: 56, height: 56, flexShrink: 0,
         background: "#F5F5F7", borderRadius: 12,
         display: "flex", alignItems: "center", justifyContent: "center",
         border: "1px solid rgba(0,0,0,0.04)", overflow: "hidden",
        }}>
         {item.image ? (
          <img src={item.image} alt="" style={{
           width: "78%", height: "78%", objectFit: "contain", mixBlendMode: "multiply",
          }} />
         ) : (
          <span style={{ fontSize: 22 }}>🍞</span>
         )}
        </div>

        {/* Info */}
        <div style={{ flex: 1, minWidth: 0 }}>
         <p style={{
          fontFamily: "var(--font-manrope)", fontSize: 12, fontWeight: 600,
          color: "#0F0F0F", lineHeight: 1.35, letterSpacing: "-0.01em",
          overflow: "hidden", display: "-webkit-box",
          WebkitLineClamp: 2, WebkitBoxOrient: "vertical",
          marginBottom: 6,
         }}>
          {item.name}
         </p>

         <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          {/* Qty */}
          <div style={{
           display: "inline-flex", alignItems: "center",
           background: "#F5F5F7", borderRadius: 8,
           border: "1px solid rgba(0,0,0,0.05)",
          }}>
           <button
            onClick={() => onUpdateQuantity(item.id, -1)}
            style={{
             width: 26, height: 26, display: "flex", alignItems: "center",
             justifyContent: "center", background: "none", border: "none",
             cursor: "pointer", fontFamily: "var(--font-manrope)",
             fontSize: 14, fontWeight: 400, color: "#8E8E93",
             transition: "color 0.15s",
            }}
            onMouseEnter={e => e.currentTarget.style.color = "#FF375F"}
            onMouseLeave={e => e.currentTarget.style.color = "#8E8E93"}
           >
            —
           </button>
           <span style={{
            fontFamily: "var(--font-manrope)", fontSize: 13, fontWeight: 800,
            color: "#0F0F0F", minWidth: 18, textAlign: "center",
           }}>
            {item.quantity}
           </span>
           <button
            onClick={() => onUpdateQuantity(item.id, 1)}
            style={{
             width: 26, height: 26, display: "flex", alignItems: "center",
             justifyContent: "center", background: "none", border: "none",
             cursor: "pointer", fontFamily: "var(--font-manrope)",
             fontSize: 16, fontWeight: 400, color: "#8E8E93",
             transition: "color 0.15s",
            }}
            onMouseEnter={e => e.currentTarget.style.color = "#FF375F"}
            onMouseLeave={e => e.currentTarget.style.color = "#8E8E93"}
           >
            +
           </button>
          </div>

          {/* Price */}
          <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end" }}>
           {item.oldPrice && (
            <span style={{
             fontFamily: "var(--font-manrope)", fontSize: 10, fontWeight: 500,
             color: "#C7C7CC", textDecoration: "line-through",
            }}>
             {item.oldPrice * item.quantity}
            </span>
           )}
           <span style={{
            fontFamily: "var(--font-manrope)", fontSize: 14, fontWeight: 800,
            letterSpacing: "-0.02em", color: "#0F0F0F",
           }}>
            {item.price * item.quantity} ₽
           </span>
          </div>
         </div>
        </div>
       </div>
      ))}
     </div>
    )}
   </div>

   {/* ── Footer ── */}
   <div style={{
    padding: "14px 22px 22px",
    borderTop: "1px solid rgba(0,0,0,0.05)",
    boxShadow: "0 -8px 24px rgba(0,0,0,0.03)",
   }}>
    {/* Итого */}
    <div style={{ marginBottom: 14 }}>
     <p style={{
      fontFamily: "var(--font-manrope)", fontSize: 11, fontWeight: 600,
      color: "#8E8E93", letterSpacing: "0.02em", marginBottom: 2,
     }}>
      Итого
     </p>
     <p style={{
      fontFamily: "var(--font-manrope)", fontSize: 30, fontWeight: 800,
      letterSpacing: "-0.045em", color: "#0F0F0F", lineHeight: 1,
     }}>
      {total} ₽
     </p>
    </div>

    {/* CTA */}
    <button
     disabled={cart.length === 0}
     style={{
      width: "100%", height: 50, borderRadius: 14, border: "none",
      background: cart.length === 0 ? "#E5E5EA" : "linear-gradient(180deg, #D18A45 0%, #B86F2E 100%)",
      color: cart.length === 0 ? "#AEAEB2" : "#fff",
      fontFamily: "var(--font-manrope)", fontSize: 15, fontWeight: 800,
      letterSpacing: "-0.01em", cursor: cart.length === 0 ? "not-allowed" : "pointer",
      display: "flex", alignItems: "center", justifyContent: "center",
      transition: "transform 0.25s cubic-bezier(0.16,1,0.3,1), box-shadow 0.25s, filter 0.25s",
      boxShadow: cart.length === 0 ? "none" : "0 4px 0 rgba(0,0,0,0.12), 0 8px 20px rgba(180,100,40,0.18)",
     }}
     onMouseEnter={e => {
      if (cart.length > 0) {
       e.currentTarget.style.transform = "translateY(-1px)";
       e.currentTarget.style.filter = "brightness(1.06)";
       e.currentTarget.style.boxShadow = "0 6px 0 rgba(0,0,0,0.10), 0 12px 28px rgba(180,100,40,0.24)";
      }
     }}
     onMouseLeave={e => {
      e.currentTarget.style.transform = "none";
      e.currentTarget.style.filter = "none";
      e.currentTarget.style.boxShadow = cart.length === 0 ? "none" : "0 4px 0 rgba(0,0,0,0.12), 0 8px 20px rgba(180,100,40,0.18)";
     }}
    >
     Продолжить
    </button>
   </div>
  </div>
 );
};

export default CartSidebar;
