"use client";
import React, { useState, useEffect } from "react";

const Header = () => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const h = () => setScrolled(window.scrollY > 8);
  window.addEventListener("scroll", h, { passive: true });
  return () => window.removeEventListener("scroll", h);
 }, []);

 return (
  <header
   style={{
    height: 68,
    position: "sticky",
    top: 0,
    zIndex: 100,
    display: "flex",
    alignItems: "center",
    padding: "0 28px",
    gap: 20,
    background: scrolled ? "rgba(255,255,255,0.92)" : "#fff",
    backdropFilter: scrolled ? "blur(24px) saturate(180%)" : "none",
    WebkitBackdropFilter: scrolled ? "blur(24px) saturate(180%)" : "none",
    borderBottom: `1px solid ${scrolled ? "rgba(0,0,0,0.05)" : "rgba(0,0,0,0.06)"}`,
    boxShadow: scrolled ? "0 1px 16px rgba(0,0,0,0.06)" : "none",
    transition: "all 0.4s cubic-bezier(0.16,1,0.3,1)",
   }}
  >
   {/* ── Logo ── */}
   <div style={{ display: "flex", flexDirection: "column", gap: 0, cursor: "pointer", userSelect: "none", flexShrink: 0 }}>
    <span style={{ fontFamily: "var(--font-manrope)", fontSize: 19, fontWeight: 800, letterSpacing: "-0.06em", lineHeight: 0.9, color: "#0F0F0F" }}>
     СМЫСЛ
    </span>
    <span style={{ fontFamily: "var(--font-manrope)", fontSize: 19, fontWeight: 800, letterSpacing: "-0.06em", lineHeight: 0.9, color: "#0F0F0F" }}>
     ЕСТЬ
    </span>
   </div>

   {/* ── Search ── */}
   <div style={{ flex: 1, display: "flex", justifyContent: "center" }}>
    <div
     style={{
      display: "flex",
      alignItems: "center",
      gap: 10,
      background: "rgba(118,118,128,0.08)",
      borderRadius: 12,
      padding: "0 16px",
      height: 40,
      width: "100%",
      maxWidth: 440,
      border: "1px solid transparent",
      transition: "all 0.25s cubic-bezier(0.16,1,0.3,1)",
     }}
     tabIndex={-1}
     onFocus={(e) => {
      e.currentTarget.style.background = "#fff";
      e.currentTarget.style.borderColor = "rgba(255,55,95,0.35)";
      e.currentTarget.style.boxShadow = "0 0 0 4px rgba(255,55,95,0.06)";
     }}
     onBlur={(e) => {
      if (!e.currentTarget.contains(e.relatedTarget as Node)) {
       e.currentTarget.style.background = "rgba(118,118,128,0.08)";
       e.currentTarget.style.borderColor = "transparent";
       e.currentTarget.style.boxShadow = "none";
      }
     }}
    >
     <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#AEAEB2" strokeWidth="2.2" strokeLinecap="round">
      <circle cx="11" cy="11" r="8" /><path d="m21 21-4.35-4.35" />
     </svg>
     <input
      type="text"
      placeholder="Search for croissants, sourdough..."
      style={{
       flex: 1, background: "transparent", border: "none", outline: "none",
       fontFamily: "var(--font-manrope)", fontSize: 13, fontWeight: 400,
       color: "#0F0F0F", letterSpacing: "-0.01em",
      }}
     />
    </div>
   </div>

   {/* ── Avatar ── */}
   <button
    style={{
     width: 38, height: 38, borderRadius: "50%", background: "rgba(118,118,128,0.08)",
     border: "none", cursor: "pointer", display: "flex", alignItems: "center",
     justifyContent: "center", transition: "background 0.2s, transform 0.2s",
     flexShrink: 0,
    }}
    onMouseEnter={e => { e.currentTarget.style.background = "rgba(118,118,128,0.14)"; e.currentTarget.style.transform = "scale(1.05)"; }}
    onMouseLeave={e => { e.currentTarget.style.background = "rgba(118,118,128,0.08)"; e.currentTarget.style.transform = "scale(1)"; }}
   >
    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#6E6E73" strokeWidth="1.8" strokeLinecap="round">
     <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" />
    </svg>
   </button>
  </header>
 );
};

export default Header;
