import React from "react";

interface Props {
 id: number;
 name: string;
 weight: string;
 price: number;
 oldPrice?: number;
 discount?: string;
 image: string;
 onAdd: () => void;
}

const ProductCard: React.FC<Props> = ({ name, weight, price, oldPrice, discount, image, onAdd }) => (
 <div
  className="group"
  style={{
   background: "#fff",
   padding: "14px 14px 16px",
   display: "flex",
   flexDirection: "column",
   position: "relative",
   cursor: "pointer",
   transition: "background 0.25s, box-shadow 0.35s cubic-bezier(0.16,1,0.3,1), z-index 0s",
  }}
  onMouseEnter={e => {
   e.currentTarget.style.background = "#FAFAFA";
   e.currentTarget.style.boxShadow = "0 16px 40px rgba(0,0,0,0.07)";
   e.currentTarget.style.zIndex = "5";
  }}
  onMouseLeave={e => {
   e.currentTarget.style.background = "#fff";
   e.currentTarget.style.boxShadow = "none";
   e.currentTarget.style.zIndex = "auto";
  }}
 >
  {/* Discount badge */}
  {discount && (
   <span style={{
    position: "absolute", top: 10, left: 10, zIndex: 10,
    background: "#FF375F", color: "#fff",
    fontFamily: "var(--font-manrope)", fontSize: 10, fontWeight: 800,
    padding: "2px 7px", borderRadius: 100, letterSpacing: "0.02em",
   }}>
    {discount}
   </span>
  )}

  {/* Image */}
  <div style={{
   position: "relative", aspectRatio: "1", display: "flex",
   alignItems: "center", justifyContent: "center",
   background: "#F5F5F7", borderRadius: 16, overflow: "hidden",
   marginBottom: 10,
   transition: "transform 0.6s cubic-bezier(0.16,1,0.3,1)",
  }}
   className="group-hover:[transform:scale(1.03)]"
  >
   <img
    src={image} alt={name} loading="lazy"
    style={{ width: "82%", height: "82%", objectFit: "contain", mixBlendMode: "multiply" }}
   />
  </div>

  {/* Name */}
  <p
   style={{
    fontFamily: "var(--font-manrope)", fontSize: 12, fontWeight: 600,
    color: "#0F0F0F", lineHeight: 1.4, letterSpacing: "-0.01em",
    overflow: "hidden", display: "-webkit-box",
    WebkitLineClamp: 2, WebkitBoxOrient: "vertical",
    minHeight: 34, marginBottom: 2,
    transition: "color 0.2s",
   }}
   className="group-hover:!text-[#FF375F]"
  >
   {name}
  </p>

  {/* Weight + "Снизили цену" */}
  <p style={{
   fontFamily: "var(--font-manrope)", fontSize: 10, fontWeight: 600,
   color: "#C7C7CC", letterSpacing: "0.03em", marginBottom: 8,
  }}>
   {weight}
   {oldPrice && (
    <span style={{ marginLeft: 4, color: "#30D158", fontWeight: 700 }}>· Снизили цену</span>
   )}
  </p>

  {/* Price row */}
  <div style={{ marginTop: "auto", display: "flex", alignItems: "flex-end", justifyContent: "space-between" }}>
   <div style={{ display: "flex", alignItems: "baseline", gap: 5 }}>
    {oldPrice && (
     <span style={{
      fontFamily: "var(--font-manrope)", fontSize: 11, fontWeight: 500,
      color: "#C7C7CC", textDecoration: "line-through",
     }}>
      {oldPrice}
     </span>
    )}
    <span style={{
     fontFamily: "var(--font-manrope)", fontSize: 16, fontWeight: 800,
     letterSpacing: "-0.03em", color: "#0F0F0F",
    }}>
     {price} ₽
    </span>
   </div>

   {/* Add button */}
   <button
    onClick={(e) => { e.stopPropagation(); onAdd(); }}
    aria-label="В корзину"
    style={{
     width: 28, height: 28, borderRadius: "50%",
     background: "#FFF0F3", border: "none",
     display: "flex", alignItems: "center", justifyContent: "center",
     cursor: "pointer", color: "#FF375F", flexShrink: 0,
     transition: "background 0.2s, color 0.2s, transform 0.3s cubic-bezier(0.34,1.56,0.64,1)",
     boxShadow: "0 1px 4px rgba(255,55,95,0.10)",
    }}
    onMouseEnter={e => {
     e.currentTarget.style.background = "#FF375F";
     e.currentTarget.style.color = "#fff";
     e.currentTarget.style.transform = "rotate(90deg) scale(1.15)";
     e.currentTarget.style.boxShadow = "0 4px 12px rgba(255,55,95,0.25)";
    }}
    onMouseLeave={e => {
     e.currentTarget.style.background = "#FFF0F3";
     e.currentTarget.style.color = "#FF375F";
     e.currentTarget.style.transform = "none";
     e.currentTarget.style.boxShadow = "0 1px 4px rgba(255,55,95,0.10)";
    }}
   >
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round">
     <path d="M12 5v14M5 12h14" />
    </svg>
   </button>
  </div>
 </div>
);

export default ProductCard;
